#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Google Service Account
 *
 * Description: Use a specific Google service account for authentication.
 * Best for GCP automation and CI/CD.
 *
 * Prerequisites:
 * - Google service account created
 * - Service account has permissions to Databricks workspace
 * - Service account key file (JSON) downloaded
 *
 * Setup:
 * 1. Create service account in GCP Console
 * 2. Grant service account permissions to Databricks workspace
 * 3. Create and download service account key (JSON file)
 *
 * Run:
 * ```bash
 * DATABRICKS_HOST="https://your-workspace.gcp.databricks.com" \
 * GOOGLE_CREDENTIALS="/path/to/service-account-key.json" \
 * npx ts-node examples/auth/google-service-account.ts
 * ```
 *
 * Or with service account email (for impersonation):
 * ```bash
 * DATABRICKS_HOST="https://your-workspace.gcp.databricks.com" \
 * DATABRICKS_GOOGLE_SERVICE_ACCOUNT="sa@project.iam.gserviceaccount.com" \
 * npx ts-node examples/auth/google-service-account.ts
 * ```
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        googleServiceAccount: process.env.DATABRICKS_GOOGLE_SERVICE_ACCOUNT,
        // Or use GOOGLE_CREDENTIALS env var pointing to JSON key file
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(
            `✓ Successfully authenticated as GCP service account: ${user.userName}`
        );
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${config.host}`);
        if (config.googleServiceAccount) {
            console.log(`  Service Account: ${config.googleServiceAccount}`);
        }
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error("\nMake sure you have set:");
        console.error("  - DATABRICKS_HOST");
        console.error("  - GOOGLE_CREDENTIALS (path to JSON key file)");
        console.error(
            "  OR DATABRICKS_GOOGLE_SERVICE_ACCOUNT (service account email)"
        );
        process.exit(1);
    }
}

main().catch(console.error);
